import bisect

class RecentCounter:

    def __init__(self):
        self.times = []

    def ping(self, t: int) -> int:
        self.times.append(t)
        lower = t - 3000
        idx = bisect.bisect_left(self.times, lower)
        return len(self.times) - idx
